const body = $json.body || {};
const callbackId = String(body.callback_id || '').trim();
const sessionId = String(body.session_id || '').trim();
const ttl = Number(body.ttl_seconds || 3600);
if (!callbackId) {
  return [{ json: { claimed: false, error: 'missing callback_id' } }];
}
const store = this.getWorkflowStaticData('global');
if (!store.callbackClaims) store.callbackClaims = {};
const nowMs = Date.now();
for (const [key, value] of Object.entries(store.callbackClaims)) {
  if (!value || !value.expires_at_ms || Number(value.expires_at_ms) <= nowMs) delete store.callbackClaims[key];
}
if (store.callbackClaims[callbackId]) {
  return [{ json: { claimed: false, callback_id: callbackId, session_id: sessionId, reason: 'duplicate' } }];
}
store.callbackClaims[callbackId] = {
  session_id: sessionId,
  claimed_at_ms: nowMs,
  expires_at_ms: nowMs + (ttl * 1000)
};
return [{ json: { claimed: true, callback_id: callbackId, session_id: sessionId, ttl_seconds: ttl } }];

const body = $json.body || {};
const sessionId = String(body.session_id || '').trim();
if (!sessionId) {
  return [{ json: { ok: false, error: 'missing session_id' } }];
}
const store = this.getWorkflowStaticData('global');
if (!store.sessionContext) store.sessionContext = {};
store.sessionContext[sessionId] = {
  last_callback_id: String(body.last_callback_id || ''),
  last_action: String(body.last_action || ''),
  updated_at: body.updated_at || new Date().toISOString()
};
return [{ json: { ok: true, session_id: sessionId, context: store.sessionContext[sessionId] } }];
